  ('elementary-10ced7e2-moex-00821', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-110-21e891bc', 'sub-elementary-10ced7e2-01', NULL, 'single_choice', '甲乙夫妻二人均為公務人員，膝下無子女，甲意外死亡，依公務人員退休資遣撫卹法規定，甲之遺族（妻 乙及父母）領受遺族撫卹金之比例為何？', '["乙再婚領撫卹金1/2、甲父母各領撫卹金1/4", "乙未再婚領撫卹金1/2、甲父母各領撫卹金1/4", "乙與甲父母各領撫卹金1/3", "得由乙與甲父母三人決定支領人及支領比例"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:48+00:00", "source_pdf_sha1": "a9ea86dba62c", "answer_pdf_sha1": "dfbc0bd4bafe", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "506", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人事行政大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
